/**
 * Chat API Route Handler
 * タスク3.1-3.4: 完全統合版
 */

import { NextRequest } from 'next/server';
import { z } from 'zod';
import { detectPII } from '@/server/lib/validation/pii';
import { searchFiles } from '@/server/lib/gemini/file-search-service';
import { buildSystemPrompt } from '@/server/lib/prompts/template-engine';
import { generateStreamingResponse } from '@/server/lib/gemini/gateway';
import type { ChatRequest, ChatMetadata } from '@/types/chat';
import type { CoreMessage } from 'ai';
import { logger } from '@/server/lib/logger';

// 会話履歴の最大件数（システムプロンプト除く）
const MAX_HISTORY = 10;

// 許可するオリジン一覧
const ALLOWED_ORIGINS: string[] = [
  // 本番環境
  'https://wmg2027.jp',
  'https://www.wmg2027.jp',
  'https://form.wmg2027.jp',
  // ステージング・開発環境
  'https://develop.wmg2027.jp',
  'https://dev.wmg2027.jp',
  // チャットボット自身（直接アクセス用）
  'https://wmg2027-ai-chatbot.vercel.app',
  // Preview環境
  'https://wmg2027-chatbot-preview.vercel.app',
];

// 開発環境では localhost を許可
if (process.env.NODE_ENV === 'development') {
  ALLOWED_ORIGINS.push(
    'http://localhost:3000',
    'http://localhost:4321' // Astro dev server
  );
}

/**
 * Origin を検証し、許可されていない場合は false を返す
 */
function isOriginAllowed(origin: string | null): boolean {
  // Origin がない場合（同一オリジンリクエスト）は許可
  if (!origin) return true;
  return ALLOWED_ORIGINS.includes(origin);
}

/**
 * CORS ヘッダーを生成
 */
function getCorsHeaders(origin: string | null): HeadersInit {
  const headers: HeadersInit = {
    'Content-Type': 'application/json',
  };

  if (origin && ALLOWED_ORIGINS.includes(origin)) {
    headers['Access-Control-Allow-Origin'] = origin;
    headers['Vary'] = 'Origin';
  }

  return headers;
}

// Route configuration for Edge Runtime
export const fetchCache = 'force-no-store';
export const revalidate = 0;
export const dynamic = 'force-dynamic';
export const runtime = 'edge';

// Zod schema for request validation
const ChatMessageSchema = z.object({
  role: z.enum(['user', 'assistant', 'system']),
  // Vercel AI SDK は content: string だが、parts 由来で content が配列になるケースにも備える
  content: z.union([
    z.string().min(1),
    z
      .array(
        z.object({
          type: z.string().optional(),
          text: z.string().optional(),
        })
      )
      .min(1),
  ]),
});

const ChatRequestSchema = z.object({
  messages: z.array(ChatMessageSchema).min(1),
  locale: z.string().min(1), // IETF BCP 47, 必須
  userAgent: z.string().optional(),
  traceId: z.string().optional(),
});

/**
 * OPTIONS: プリフライトリクエスト対応
 */
export async function OPTIONS(request: NextRequest) {
  const origin = request.headers.get('origin');

  if (isOriginAllowed(origin)) {
    return new Response(null, {
      status: 204,
      headers: {
        'Access-Control-Allow-Origin': origin || '*',
        'Access-Control-Allow-Methods': 'POST, OPTIONS',
        'Access-Control-Allow-Headers': 'Content-Type',
        'Access-Control-Max-Age': '86400',
        Vary: 'Origin',
      },
    });
  }

  return new Response(null, { status: 403 });
}

export async function POST(request: NextRequest) {
  const startTime = Date.now();
  const origin = request.headers.get('origin');

  // Origin 検証
  if (!isOriginAllowed(origin)) {
    logger.warn({ origin }, 'Blocked request from unauthorized origin');
    return new Response(JSON.stringify({ error: 'Forbidden' }), {
      status: 403,
      headers: getCorsHeaders(origin),
    });
  }

  try {
    // Parse and validate request body
    const body = await request.json();

    // locale が欠落してもデフォルトで日本語にフォールバック
    if (!body.locale) {
      const acceptLanguage = request.headers.get('accept-language') || '';
      body.locale = acceptLanguage.startsWith('en')
        ? 'en'
        : acceptLanguage.startsWith('zh')
          ? 'zh'
          : acceptLanguage.startsWith('ko')
            ? 'ko'
            : 'ja';
    }

    // parts 形式の content を文字列に正規化
    if (Array.isArray(body.messages)) {
      body.messages = body.messages.map((m: any) => ({
        ...m,
        content: normalizeContent(m.content),
      }));
    }

    const validationResult = ChatRequestSchema.safeParse(body);

    if (!validationResult.success) {
      return new Response(
        JSON.stringify({ error: 'Invalid request format', details: validationResult.error.errors }),
        { status: 400, headers: getCorsHeaders(origin) }
      );
    }

    const chatRequest: ChatRequest = validationResult.data as ChatRequest;

    // PII Detection - check all user messages
    for (const message of chatRequest.messages) {
      if (message.role === 'user') {
        const piiResult = detectPII(message.content);
        if (piiResult.found) {
          return new Response(
            JSON.stringify({
              error:
                '個人情報が検出されました。メールアドレス、電話番号、住所などの個人情報は入力しないでください。',
              pii_type: piiResult.type,
            }),
            { status: 422, headers: getCorsHeaders(origin) }
          );
        }
      }
    }

    // Generate request metadata
    const metadata: ChatMetadata = {
      requestId: crypto.randomUUID(),
      timestamp: new Date().toISOString(),
      locale: chatRequest.locale,
      userAgent: chatRequest.userAgent || request.headers.get('user-agent') || undefined,
    };

    logger.info(
      {
        requestId: metadata.requestId,
        locale: chatRequest.locale,
        messageCount: chatRequest.messages.length,
      },
      'Chat request received'
    );

    // Get last user message as query
    const lastUserMessage = chatRequest.messages.filter(m => m.role === 'user').pop();

    if (!lastUserMessage) {
      return new Response(JSON.stringify({ error: 'No user message found' }), {
        status: 400,
        headers: getCorsHeaders(origin),
      });
    }

    // タスク3.2: File Search統合 - Top3取得
    const searchResult = await searchFiles(lastUserMessage.content);

    if (!searchResult.success) {
      logger.error(
        {
          requestId: metadata.requestId,
          error: searchResult.error,
        },
        'File search failed'
      );

      // File Search失敗時はコンテキストなしで応答を生成
      // (ユーザーには一般的な案内を返す)
    }

    const contexts = searchResult.results;
    logger.info(
      {
        requestId: metadata.requestId,
        contextCount: contexts.length,
      },
      'Retrieved contexts'
    );

    // タスク3.3: システムプロンプト構築（コンテキスト付き）
    const systemPrompt = buildSystemPrompt(contexts, chatRequest.locale);

    // 会話履歴を制限（直近N件）+ messages配列構築
    const recentMessages = chatRequest.messages.slice(-MAX_HISTORY);
    const messages: CoreMessage[] = [
      { role: 'system', content: systemPrompt },
      ...recentMessages.map(m => ({
        role: m.role as 'user' | 'assistant',
        content: m.content,
      })),
    ];

    logger.info(
      {
        requestId: metadata.requestId,
        historyCount: recentMessages.length,
      },
      'Building messages with conversation history'
    );

    // タスク3.4: Geminiストリーミング統合（会話履歴対応）
    const streamResult = await generateStreamingResponse(messages);

    const latency = Date.now() - startTime;
    logger.info(
      {
        requestId: metadata.requestId,
        latency,
      },
      'Response sent'
    );

    // SSEレスポンスとして返す
    return streamResult.toDataStreamResponse();
  } catch (error) {
    logger.error({ error }, 'Chat API error');

    // フォールバックメッセージ
    if (error instanceof Error && error.message.includes('一時的に利用できません')) {
      return new Response(JSON.stringify({ error: error.message }), {
        status: 503,
        headers: getCorsHeaders(origin),
      });
    }

    return new Response(JSON.stringify({ error: 'Internal server error' }), {
      status: 500,
      headers: getCorsHeaders(origin),
    });
  }
}

/**
 * content が配列（parts）で届いた場合にテキストを抽出し結合する
 */
function normalizeContent(content: unknown): string {
  if (typeof content === 'string') return content;

  if (Array.isArray(content)) {
    const texts = content
      .map(part => (part as { text?: string }).text)
      .filter((t): t is string => typeof t === 'string' && t.length > 0);
    if (texts.length > 0) return texts.join('\n');
  }

  return ''; // validation で弾かれる
}

